                {[3, 5, 10, 20].map(r => (
                <button key={r} onClick={() => { setRounds(r); setRoundsInput(r.toString()); }} className={`py-2 rounded-lg font-bold text-sm border ${rounds === r ? 'bg-yellow-500 text-black border-yellow-500' : 'bg-slate-800 text-gray-400 border-slate-600'}`}>{r}</button>
