export const SetupOnline: React.FC<SetupProps> = ({ displayName, userId, setMyOnlineId }) => {
  const navigate = useNavigate();
  const setRoomCode = useGameStore(s => s.setRoomCode);
  const setGameState = useGameStore(s => s.setGameState);

  const [joinCode, setJoinCode] = useState('');
  const [isJoining, setIsJoining] = useState(false);

  const handleCreate = async () => {
    const { code, error } = await createRoom(displayName, userId);
    if (error) return alert(error.message);

    setRoomCode(code);
    setGameState({ gameMode: 'ONLINE_HOST' });
    setMyOnlineId(0);
    localStorage.setItem('TRI_STACK_SESSION', JSON.stringify({ code, playerId: 0 }));
    navigate('/lobby');
  };

  const handleJoin = async () => {
    if (isJoining) return;
    setIsJoining(true);
    const { success, error, playerId } = await joinRoom(joinCode.toUpperCase(), displayName);
    if (!success) {
      alert(error);
      setIsJoining(false);
      return;
    }

    setRoomCode(joinCode.toUpperCase());
    setGameState({ gameMode: 'ONLINE_CLIENT' });
    setMyOnlineId(playerId!);
    localStorage.setItem('TRI_STACK_SESSION', JSON.stringify({ code: joinCode.toUpperCase(), playerId }));
    navigate('/lobby');
  };

  return (
    <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-3xl font-bold text-yellow-500 mb-8">Online Play</h1>
        <div className="bg-slate-900/80 p-8 rounded-2xl border border-white/10 w-full max-w-md">
           <button onClick={() => navigate('/')} className="text-gray-400 flex items-center gap-1 mb-6"><ChevronLeft size={20} /> Back</button>
           <button onClick={handleCreate} className="w-full bg-yellow-500 hover:bg-yellow-400 text-black p-6 rounded-xl font-bold text-xl flex flex-col items-center justify-center gap-2 shadow-lg mb-6">
               <Wifi size={32} /> Create New Room
           </button>
           <div className="bg-black/30 p-4 rounded-xl border border-white/10">
               <label className="text-xs text-gray-400 font-bold uppercase mb-2 block">Join Existing</label>
               <div className="flex gap-2">
                  <input type="text" maxLength={4} placeholder="CODE" value={joinCode} onChange={(e) => setJoinCode(e.target.value.toUpperCase())} className="bg-slate-800 text-white font-mono text-center text-xl p-3 rounded-lg w-full border border-slate-600 uppercase tracking-widest" />
                  <button onClick={handleJoin} disabled={isJoining} className="bg-blue-600 hover:bg-blue-500 text-white px-6 rounded-lg font-bold flex items-center justify-center min-w-[80px]">
                    {isJoining ? <Loader2 className="animate-spin" size={20} /> : 'JOIN'}
                  </button>
               </div>
           </div>
        </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useGameStore } from '../store/gameStore';
import { GamePhase, GameMode } from '../../types';
import { decideBotAction } from '../../services/gameLogic';
import { subscribeToRoom, leaveRoom, resetRoomToLobby } from '../../services/online';
import Card from '../../components/Card';
import { RefreshCw, Trophy, Users, AlertCircle, Hand, ChevronRight, EyeOff, Eye, Bot, ArrowRight, LogOut, Globe } from 'lucide-react';
import { calculateHandValue } from '../../services/gameLogic';

interface GameProps {
  myOnlineId: number | null;
  resetSession: () => void;
}

const Game: React.FC<GameProps> = ({ myOnlineId, resetSession }) => {
  const navigate = useNavigate();
  // State Selectors
  const state = useGameStore();
  const { 
    players, currentPlayerIndex, roundJoker, deck, openDeck, phase, 
    roundNumber, totalRounds, gameMode, pendingDiscard, pendingToss,
    tossedThisTurn, isTransitioning, selectedCardIds,
    _roomCode
  } = state;

  const [showExitConfirm, setShowExitConfirm] = useState(false);

  const currentPlayer = players[currentPlayerIndex] || { 
    id: -1, 
    name: '...', 
    isBot: false, 
    hand: [], 
    score: 0, 
    totalScore: 0, 
    lastAction: '' 
  };

  // Perspective Logic
  let bottomPlayer = currentPlayer;
  let opponentsToRender = players.filter(p => p.id !== currentPlayer.id);

  if (gameMode === 'SINGLE_PLAYER' && players.length > 0) {
    bottomPlayer = players[0];
    opponentsToRender = players.filter(p => p.id !== 0);
  } else if ((gameMode === 'ONLINE_HOST' || gameMode === 'ONLINE_CLIENT') && myOnlineId !== null) {
    bottomPlayer = players.find(p => p.id === myOnlineId) || currentPlayer;
    opponentsToRender = players.filter(p => p.id !== myOnlineId);
  }

  const isMyTurnOnline = (gameMode === 'ONLINE_HOST' || gameMode === 'ONLINE_CLIENT') 
      ? currentPlayer.id === myOnlineId 
      : true;

  const isPlayerTurn = !isTransitioning 
      && !currentPlayer.isBot 
      && phase !== GamePhase.ROUND_END 
      && phase !== GamePhase.MATCH_END
      && isMyTurnOnline;

  const isBotThinking = gameMode === 'SINGLE_PLAYER' && currentPlayer.isBot && !isTransitioning && phase !== GamePhase.ROUND_END;

  // --- Bot Logic Effect ---
  useEffect(() => {
    if (!isBotThinking) return;

    const timeout = setTimeout(() => {
      const p = currentPlayer;

      if (phase === GamePhase.PLAYER_TURN_START) {
        const action = decideBotAction(p, roundJoker, tossedThisTurn);
        if (action.type === 'SHOW') state.handleShow();
        else if (action.type === 'TOSS' && action.cardIds) {
            useGameStore.setState({ selectedCardIds: action.cardIds });
            state.handleToss();
        } else if (action.type === 'DISCARD' && action.cardIds) {
            useGameStore.setState({ selectedCardIds: action.cardIds });
            state.handleDiscard();
        }
      } 
      else if (phase === GamePhase.PLAYER_DRAW || phase === GamePhase.PLAYER_TOSSING_DRAW) {
        state.handleDraw('DECK');
      }
    }, 1500); 

    return () => clearTimeout(timeout);
  }, [phase, currentPlayerIndex, isBotThinking, tossedThisTurn, roundJoker, currentPlayer, state]);

  // --- Online Sync Effect ---
  useEffect(() => {
    if ((gameMode === 'ONLINE_HOST' || gameMode === 'ONLINE_CLIENT') && _roomCode) {
        const sub = subscribeToRoom(_roomCode, (roomData) => {
            if (roomData.status === 'WAITING') {
                navigate('/lobby'); // Return to lobby
            } else if (roomData.game_state) {
                const effectiveMode = (myOnlineId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') as GameMode;
                state.setGameState({ ...roomData.game_state, gameMode: effectiveMode });
            }
        });
        return () => { import('../../services/supabase').then(({ supabase }) => supabase.removeChannel(sub)); };
    }
  }, [gameMode, _roomCode, myOnlineId, navigate, state]);

  const handleNextRound = () => {
    if (roundNumber >= totalRounds) return;
    state.startRound(roundNumber + 1, players, gameMode);
  };

  const handleExit = () => {
    resetSession();
    if (gameMode === 'ONLINE_HOST' && _roomCode) resetRoomToLobby(_roomCode);
    else if (gameMode === 'ONLINE_CLIENT' && _roomCode && myOnlineId !== null) leaveRoom(_roomCode, myOnlineId);
    state.resetGame();
    navigate('/');
  };

  const showOpponentCards = phase === GamePhase.ROUND_END;
  const isLastRound = roundNumber >= totalRounds;
  const lowestScore = Math.min(...players.map(p => p.totalScore || 0));

  // --- TRANSITION OVERLAY ---
  if (isTransitioning) {
    return (
      <div className="h-[100dvh] bg-slate-900 flex flex-col items-center justify-center p-4 z-50">
        <div className="max-w-md w-full bg-slate-800 p-8 rounded-2xl shadow-2xl border border-yellow-500/30 text-center animate-in fade-in">
           <div className="w-20 h-20 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/20"><EyeOff size={40} className="text-white" /></div>
           <h2 className="text-2xl text-gray-400 font-serif mb-2">Turn Complete</h2>
           <p className="text-gray-500 mb-8">Please pass the device to</p>
           <h1 className="text-4xl font-bold text-white mb-8 tracking-tight">{currentPlayer.name}</h1>
           <button onClick={() => state.setTransitioning(false)} className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-3 transition-all transform hover:scale-[1.02]"><Eye size={24} /> I am {currentPlayer.name} - Ready</button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#1a2e1a]">
      {/* Top Bar */}
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-20 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={() => setShowExitConfirm(true)} className="text-red-400 hover:text-red-300 transition-colors bg-white/5 p-2 rounded-lg">
             <LogOut size={20} />
          </button>

          <h1 className="font-serif font-bold text-xl text-yellow-500 hidden md:block">TRI-STACK</h1>
          <div className="bg-slate-800 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2">
             <span className="text-gray-400">Round</span>
             <span className="font-bold text-white">{roundNumber}/{totalRounds}</span>
          </div>
          {(gameMode === 'ONLINE_HOST' || gameMode === 'ONLINE_CLIENT') && (
             <div className="flex items-center gap-2">
                <div className="bg-blue-900/50 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2 border border-blue-500/30">
                  <Globe size={12} className="text-blue-400" />
                  <span className="font-mono font-bold text-blue-200">{_roomCode}</span>
                </div>
             </div>
          )}
        </div>

        <div className="flex items-center gap-2">
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold hidden sm:inline">All {roundJoker?.rank}s are Jokers</span>
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold sm:hidden">Joker: {roundJoker?.rank}</span>
           {roundJoker && <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1"><span className="font-bold">{roundJoker.rank}</span></div>}
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className={`w-3 h-3 rounded-full ${isBotThinking ? 'bg-yellow-500' : 'bg-green-500'} animate-pulse`} />
             <span className="text-sm font-bold truncate max-w-[100px] text-white">{currentPlayer.name} {isBotThinking && '...'}</span>
           </div>
        </div>
      </div>

      {/* Game Area */}
      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents */}
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mb-2 max-h-[30vh] overflow-y-auto">
           {opponentsToRender.map(opp => (
             <div key={opp.id} className={`flex flex-col items-center p-2 rounded-lg transition-all ${opp.id === currentPlayerIndex ? 'bg-yellow-500/10 scale-105 border border-yellow-500/30' : 'bg-black/20'}`}>
                <div className="relative">
                   <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-700 rounded-full flex items-center justify-center border-2 border-slate-500">
                     {opp.isBot ? <Bot size={20} className="text-slate-300" /> : <Users size={20} className="text-slate-300" />}
                   </div>
                   {opp.hand && <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-blue-900 rounded-full flex items-center justify-center text-[10px] font-bold border border-white">{opp.hand.length}</div>}
                </div>
                <span className="text-xs font-bold mt-1 max-w-[60px] truncate">{opp.name}</span>
                <span className="text-[10px] text-yellow-400">{opp.totalScore || 0} pts</span>

                {phase === GamePhase.ROUND_END && (
                  <div className="absolute top-10 z-30 flex gap-1 bg-black/80 p-1 rounded shadow-2xl animate-in fade-in zoom-in">
                     {(opp.hand || []).map((c, i) => (<Card key={c.id || i} card={showOpponentCards ? c : undefined} small isJoker={roundJoker ? (c.rank === roundJoker.rank) : false} />))}
                     <div className="bg-white text-black text-xs font-bold p-1 rounded flex items-center">{calculateHandValue(opp.hand || [], roundJoker)}</div>
                  </div>
                )}

                {phase !== GamePhase.ROUND_END && (
                  <div className="flex -space-x-4 mt-2">
                     {(opp.hand || []).map((c, i) => (<Card key={i} small className="scale-75" />))}
                  </div>
                )}
             </div>
           ))}
        </div>

        {/* Center Table */}
        <div className="flex-1 flex items-center justify-center gap-4 md:gap-16 my-2 relative">
            <div className="flex flex-col items-center gap-2">
               <Card disabled={!isPlayerTurn || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)} onClick={() => state.handleDraw('DECK')} />
               <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Deck ({deck.length})</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openDeck.length > 0 ? (
                   <Card 
                     card={openDeck[openDeck.length - 1]}
                     isJoker={roundJoker && openDeck[openDeck.length - 1].rank === roundJoker.rank}
                     onClick={() => state.handleDraw('OPEN')}
                     disabled={!isPlayerTurn || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)}
                   />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/20 rounded-xl flex items-center justify-center"><span className="text-white/20 text-xs">Empty</span></div>
                 )}
                 <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Open Pile</span>
              </div>

              {pendingDiscard && (
                <div className="flex flex-col items-center gap-2 relative animate-in slide-in-from-left-4 fade-in">
                  <div className="relative">
                    <Card card={pendingDiscard} isJoker={roundJoker && pendingDiscard.rank === roundJoker.rank} disabled={true} className="opacity-70 ring-2 ring-yellow-500/50" />
                    <div className="absolute inset-0 flex items-center justify-center"><ArrowRight className="text-white drop-shadow-lg" size={32} /></div>
                  </div>
                  <span className="text-xs uppercase tracking-wider font-bold text-yellow-400 animate-pulse">Discarding...</span>
                </div>
              )}

              {pendingToss.length > 0 && (
                 <div className="flex flex-col items-center gap-1 relative animate-in slide-in-from-left-4 fade-in">
                    <div className="relative flex -space-x-8">
                       {pendingToss.map(c => (<Card key={c.id} card={c} isJoker={roundJoker && c.rank === roundJoker.rank} disabled={true} className="opacity-70 ring-2 ring-blue-500/50" />))}
                       <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><RefreshCw className="text-white drop-shadow-lg animate-spin" size={32} /></div>
                    </div>
                    <span className="text-xs uppercase tracking-wider font-bold text-blue-400 animate-pulse">Tossing...</span>
                 </div>
              )}
            </div>

            {/* End Round Modal */}
            {phase === GamePhase.ROUND_END && (
               <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
                 <div className="bg-slate-900/95 p-6 rounded-2xl shadow-2xl border border-yellow-500/30 backdrop-blur-sm max-w-sm w-full text-center m-4 animate-in fade-in zoom-in">
                    <h2 className="text-2xl font-serif font-bold text-white mb-1">{isLastRound ? "Match Complete" : "Round Over"}</h2>
                    <p className="text-gray-400 mb-6 text-xs uppercase tracking-widest">{isLastRound ? "Final Standings" : "Round Summary"}</p>

                    <div className="space-y-3 mb-8 text-left max-h-[50vh] overflow-y-auto pr-1">
                       {players
                         .sort((a, b) => isLastRound ? (a.totalScore - b.totalScore) : 0)
                         .map(p => {
                           const isWinner = isLastRound && (p.totalScore || 0) === lowestScore;
                           const handValue = calculateHandValue(p.hand, roundJoker);

                           return (
                             <div key={p.id} className={`flex justify-between items-center p-3 rounded-lg border ${isWinner ? 'bg-yellow-500/10 border-yellow-500/50' : 'bg-slate-800 border-white/5'}`}>
                                <span className={`flex items-center gap-2 ${p.id === currentPlayerIndex ? 'text-blue-400 font-bold' : (isWinner ? 'text-yellow-400 font-bold' : 'text-gray-300')}`}>
                                  {isWinner && <Trophy size={14} className="text-yellow-500" />} {p.name} {p.id === currentPlayerIndex && <span className="text-xs bg-blue-900 text-blue-200 px-1 rounded">CALLER</span>}
                                </span>
                                <div className="flex items-center gap-3">
                                   <div className="flex flex-col items-end">
                                      <span className="text-[10px] uppercase text-gray-500 font-bold">Hand</span>
                                      <span className="text-sm font-bold text-gray-400">{handValue}</span>
                                   </div>
                                   <div className="w-px h-8 bg-white/10"></div>
                                   <div className="flex flex-col items-end">
                                      <span className="text-[10px] uppercase text-gray-500 font-bold">Round</span>
                                      <span className={`text-sm font-bold ${p.score === 0 ? 'text-green-400' : 'text-red-400'}`}>{p.score > 0 ? `+${p.score}` : p.score}</span>
                                   </div>
                                   <div className="w-px h-8 bg-white/10"></div>
                                   <div className="flex flex-col items-end min-w-[30px]">
                                       <span className="text-[10px] uppercase text-gray-500 font-bold">Total</span>
                                       <span className={`text-lg font-bold ${isWinner ? 'text-yellow-400' : 'text-white'}`}>{p.totalScore || 0}</span>
                                   </div>
                                </div>
                             </div>
                           );
                       })}
                    </div>
                    {((gameMode !== 'ONLINE_CLIENT' && gameMode !== 'ONLINE_HOST') || (gameMode === 'ONLINE_HOST' && myOnlineId === 0)) && (
                       <button 
                         onClick={isLastRound ? handleExit : handleNextRound} 
                         className={`w-full font-bold py-3 rounded-lg flex items-center justify-center gap-2 ${isLastRound ? 'bg-green-600 hover:bg-green-500 text-white' : 'bg-yellow-500 hover:bg-yellow-400 text-black'}`}
                       >
                         {isLastRound ? (gameMode === 'ONLINE_HOST' ? 'Return to Lobby' : 'Back to Menu') : 'Next Round'} {isLastRound ? <RefreshCw size={18} /> : <ChevronRight size={18} />}
                       </button>
                    )}
                    {gameMode === 'ONLINE_CLIENT' && (
                       <div className="flex flex-col gap-2">
                          <div className="text-sm text-yellow-500 animate-pulse">{isLastRound ? 'Waiting for Host...' : 'Waiting for Host...'}</div>
                          <button onClick={() => setShowExitConfirm(true)} className="text-red-400 hover:text-red-300 text-sm underline">Leave Room</button>
                       </div>
                    )}
                 </div>
               </div>
            )}
        </div>

        {/* ACTIVE PLAYER Controls */}
        <div className="flex flex-col items-center gap-4 pb-8 shrink-0">
           {isPlayerTurn && currentPlayer.id === bottomPlayer.id ? (
             <div className="flex items-center gap-2 bg-black/40 backdrop-blur-md p-2 rounded-full border border-white/10 shadow-xl transition-all animate-in slide-in-from-bottom-4 z-10 scale-90 md:scale-100">
                {phase === GamePhase.PLAYER_TURN_START && (
                  <>
                    <button onClick={state.handleShow} className="bg-red-600 hover:bg-red-500 text-white px-4 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm shadow-lg shadow-red-900/50"><AlertCircle size={16} /> SHOW</button>
                    <div className="w-px h-6 bg-white/20 mx-1"></div>
                    <button onClick={state.handleToss} disabled={selectedCardIds.length !== 2 || tossedThisTurn} className={`px-4 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm transition-all ${selectedCardIds.length === 2 && !tossedThisTurn ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/50' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}><RefreshCw size={16} /> TOSS (2)</button>
                    <button onClick={state.handleDiscard} disabled={selectedCardIds.length !== 1} className={`px-4 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm transition-all ${selectedCardIds.length === 1 ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-900/50' : 'bg-slate-700 text-slate-500 cursor-not-allowed'}`}><Hand size={16} /> DISCARD (1)</button>
                  </>
                )}
                {(phase === GamePhase.PLAYER_DRAW || phase === GamePhase.PLAYER_TOSSING_DRAW) && (
                   <div className="px-4 py-2 text-white font-bold text-sm animate-pulse flex items-center gap-2"><div className="w-2 h-2 bg-yellow-400 rounded-full" />{phase === GamePhase.PLAYER_TOSSING_DRAW ? 'Toss complete. Draw a card!' : 'Draw to finish turn...'}</div>
                )}
             </div>
           ) : (
             <div className="h-10 flex items-center justify-center text-gray-400 text-sm italic">
                {currentPlayer.isBot ? 'Opponent is thinking...' : (currentPlayer.id !== bottomPlayer.id ? `Waiting for ${currentPlayer.name}...` : 'Waiting...')}
             </div>
           )}

           <div className="flex items-end justify-center -space-x-4 md:-space-x-6 h-[140px] md:h-[160px]">
              {(bottomPlayer.hand || []).map((card) => (
                <Card 
                  key={card.id} 
                  card={(!isPlayerTurn && gameMode === 'MULTIPLAYER') ? undefined : card} 
                  isJoker={roundJoker ? (card.rank === roundJoker.rank) : false}
                  selected={selectedCardIds.includes(card.id)}
                  onClick={() => state.toggleCardSelection(card.id)}
                  className={`transition-all origin-bottom ${isPlayerTurn && currentPlayer.id === bottomPlayer.id ? 'hover:z-20' : 'opacity-80'}`}
                />
              ))}
           </div>
           <div className="text-xs text-gray-400 mt-2"><span className="text-green-400 font-bold uppercase tracking-wider">{bottomPlayer.name}</span> • Total Score: <span className="text-white font-bold text-lg">{bottomPlayer.totalScore || 0}</span></div>
        </div>
      </div>

      {showExitConfirm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in">
          <div className="bg-slate-900 border border-red-500/30 p-6 rounded-2xl max-w-sm w-full text-center shadow-2xl">
             <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-4">
                <LogOut size={32} className="text-red-500" />
             </div>
             <h2 className="text-xl font-bold text-white mb-2">Leave Game?</h2>
             <p className="text-gray-400 text-sm mb-6">Your progress will be lost.</p>
             <div className="flex gap-3">
                <button onClick={() => setShowExitConfirm(false)} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 text-white rounded-xl font-bold">Cancel</button>
                <button onClick={handleExit} className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-bold">Exit</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Game;

