    supabase.auth.getSession().then(({ data: { session } }) => {
      if(mounted) {
        console.log("Session fetched", session ? "User logged in" : "No user");
        setSession(session);
        setAuthLoading(false);
      }
    }).catch((err) => {
      console.error("Auth Error:", err);
      if(mounted) setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if(mounted) setSession(session);
    });

    const savedName = localStorage.getItem(NAME_KEY);
    if (savedName) setCustomDisplayName(savedName);

    return () => {
      mounted = false;
      clearTimeout(timeout);
      subscription.unsubscribe();
    };
  }, []);

  const getDisplayName = () => {
    if (customDisplayName) return customDisplayName;
    return isGuest ? 'Guest' : (session?.user?.email?.split('@')[0] || 'Player');
  };

  const handleUpdateName = (name: string) => {
    setCustomDisplayName(name);
    localStorage.setItem(NAME_KEY, name);
  };

  // --- Session Reconnection ---
  useEffect(() => {
    const checkSession = async () => {
      const savedSession = localStorage.getItem(SESSION_KEY);
      if (savedSession) {
        console.log("Found saved session, attempting reconnect...");
        setIsReconnecting(true);
        try {
          const { code, playerId } = JSON.parse(savedSession);
          const { data: roomData, error } = await getRoomData(code);

          if (error || !roomData) {
            console.log("Saved session invalid or room closed.");
            localStorage.removeItem(SESSION_KEY);
          } else {
            console.log("Reconnected to room:", code);
            setRoomCode(code);
            setMyOnlineId(playerId);
            setIsGuest(true); 

            if (roomData.game_state) {
               const effectiveMode = (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') as GameMode;
               setGameState({ ...roomData.game_state, gameMode: effectiveMode });
            }
          }
        } catch (e) {
          console.error("Reconnection failed", e);
          localStorage.removeItem(SESSION_KEY);
        } finally {
          setIsReconnecting(false);
        }
      }
    };
    checkSession();
  }, [setRoomCode, setGameState]);

  const resetSession = () => {
    localStorage.removeItem(SESSION_KEY);
    setRoomCode('');
    setMyOnlineId(null);
    setGameState({ gameMode: null });
  };

  if (authLoading || isReconnecting) {
    return (
      <div className="h-[100dvh] w-full bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-4 z-50 fixed inset-0">
        <div className="w-12 h-12 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin"></div>
        <h2 className="font-serif text-2xl animate-pulse">Loading Tri-Stack...</h2>
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Auth onGuestPlay={() => setIsGuest(true)} />;
  }

  const commonProps = { displayName: getDisplayName(), userId: session?.user?.id || 'guest', setMyOnlineId };

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<MainMenu {...commonProps} onUpdateName={handleUpdateName} isGuest={isGuest} />} />

        <Route path="/setup/single" element={<SetupSingle {...commonProps} />} />
        <Route path="/setup/multi/:count" element={<SetupMulti />} />
        <Route path="/setup/online" element={<SetupOnline {...commonProps} />} />

        <Route path="/lobby" element={<Lobby myOnlineId={myOnlineId} resetSession={resetSession} />} />
        <Route path="/game" element={<Game myOnlineId={myOnlineId} resetSession={resetSession} />} />

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </HashRouter>
  );
};

