import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useGameStore } from '../store/gameStore';
import { subscribeToRoom, leaveRoom } from '../../services/online';
import { Users, Copy, LogOut, Play, Crown, Loader2 } from 'lucide-react';

interface LobbyProps {
  myOnlineId: number | null;
  resetSession: () => void;
}

const Lobby: React.FC<LobbyProps> = ({ myOnlineId, resetSession }) => {
  const navigate = useNavigate();
  const roomCode = useGameStore(s => s._roomCode);
  const players = useGameStore(s => s.players);
  const gameMode = useGameStore(s => s.gameMode);
  const startRound = useGameStore(s => s.startRound);
  const setGameState = useGameStore(s => s.setGameState);

  const isHost = gameMode === 'ONLINE_HOST';

  useEffect(() => {
    if (!roomCode) {
      navigate('/');
      return;
    }

    const sub = subscribeToRoom(roomCode, (roomData) => {
      if (roomData.players) {
        // Map raw players to store Player objects
        const mappedPlayers = roomData.players.map((p: any) => ({
          id: p.id,
          name: p.name,
          isBot: false,
          hand: [],
          score: 0,
          totalScore: 0,
          lastAction: 'Waiting...'
        }));

        setGameState({ players: mappedPlayers });
      }

      if (roomData.status === 'PLAYING' && roomData.game_state) {
         const effectiveMode = (myOnlineId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT');
         setGameState({ ...roomData.game_state, gameMode: effectiveMode });
         navigate('/game');
      }
    });

    return () => {
      import('../../services/supabase').then(({ supabase }) => supabase.removeChannel(sub));
    };
  }, [roomCode, navigate, setGameState, myOnlineId]);

  const handleStartGame = async () => {
    if (!isHost) return;
    startRound(1, players, 'ONLINE_HOST');
    navigate('/game');
  };

  const handleLeave = async () => {
    if (roomCode && myOnlineId !== null) {
      await leaveRoom(roomCode, myOnlineId);
    }
    resetSession();
    navigate('/');
  };

  const copyCode = () => {
    navigator.clipboard.writeText(roomCode);
    alert('Room code copied!');
  };

  return (
    <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
      <div className="bg-slate-900/80 p-8 rounded-2xl border border-white/10 w-full max-w-md backdrop-blur-sm">
        <div className="flex justify-between items-center mb-8">
           <h1 className="text-2xl font-bold text-white flex items-center gap-2">
             <Users className="text-yellow-500" /> Lobby
           </h1>
           <button onClick={handleLeave} className="text-red-400 hover:text-red-300 bg-red-900/20 p-2 rounded-lg transition-colors">
             <LogOut size={20} />
           </button>
        </div>

        <div className="bg-black/40 p-4 rounded-xl border border-white/10 mb-6 text-center">
           <p className="text-gray-400 text-xs uppercase font-bold tracking-widest mb-1">Room Code</p>
           <div className="flex items-center justify-center gap-3">
              <span className="text-4xl font-mono text-blue-400 font-bold tracking-widest">{roomCode}</span>
              <button onClick={copyCode} className="text-gray-500 hover:text-white"><Copy size={20} /></button>
           </div>
        </div>

        <div className="space-y-3 mb-8">
           <div className="flex justify-between items-end border-b border-white/10 pb-2">
              <span className="text-gray-400 text-sm">Players ({players.length}/10)</span>
              {isHost && players.length < 2 && <span className="text-yellow-500 text-xs animate-pulse">Waiting for players...</span>}
           </div>

           <div className="max-h-[30vh] overflow-y-auto pr-2 space-y-2">
              {players.map((p) => (
                <div key={p.id} className={`flex items-center gap-3 p-3 rounded-lg ${p.id === myOnlineId ? 'bg-blue-900/30 border border-blue-500/30' : 'bg-slate-800'}`}>
                   <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-sm font-bold text-white relative">
                      {p.name.charAt(0).toUpperCase()}
                      {p.id === 0 && <Crown size={12} className="absolute -top-1 -right-1 text-yellow-500 fill-yellow-500" />}
                   </div>
                   <span className="text-white font-medium flex-1 truncate">{p.name} {p.id === myOnlineId && '(You)'}</span>
                </div>
              ))}
           </div>
        </div>

        {isHost ? (
          <button 
            onClick={handleStartGame} 
            disabled={players.length < 2}
            className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-2 transition-all ${players.length >= 2 ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-900/20' : 'bg-slate-700 text-gray-500 cursor-not-allowed'}`}
          >
            Start Game <Play size={20} />
          </button>
        ) : (
          <div className="text-center p-4 bg-yellow-500/10 rounded-xl border border-yellow-500/20">
             <div className="flex justify-center mb-2"><Loader2 className="animate-spin text-yellow-500" size={24} /></div>
             <p className="text-yellow-200 font-bold">Waiting for Host to start...</p>
          </div>
        )}
      </div>
    </div>
  );
};

