        isBot: false,
        hand: [],
        score: 0,
        totalScore: 0,
        lastAction: 'Joined'
    }));

    // Explicitly pass rounds to startRound to ensure it's captured
    startRound(1, players, 'ONLINE_HOST', rounds);
    navigate('/game');
  };

  const handleLeave = () => {
    resetSession();
    if (myOnlineId !== null && roomCode) leaveRoom(roomCode, myOnlineId);
    navigate('/');
  };

  // Logic to update rounds from input or buttons
  const updateRounds = (val: string | number) => {
      let numVal = typeof val === 'string' ? parseInt(val) : val;
      if (isNaN(numVal)) numVal = 0; // Temporary allow 0 for typing

      setRoundsInput(val.toString());
      if (numVal > 0) setRounds(Math.min(Math.max(numVal, 1), 100)); // Clamp 1-100 for logic
  };

  const handleBlur = () => {
      // On blur, ensure the input display matches the clamped value
      let numVal = parseInt(roundsInput);
      if (isNaN(numVal) || numVal < 1) numVal = 1;
      if (numVal > 100) numVal = 100;
      setRoundsInput(numVal.toString());
      setRounds(numVal);
