                    <Users size={16}/> Players Joined ({lobbyPlayers.length}/10)
                 </h3>
                 <div className="flex flex-col gap-3 max-h-[300px] overflow-y-auto pr-1 custom-scrollbar">
                    {lobbyPlayers.map(p => (
                       <div key={p.id} className="bg-[#1e293b] p-3 px-4 rounded-xl flex items-center justify-between shadow-sm border border-white/5">
                          <span className="font-bold text-white text-base font-sans">{p.name}</span>
                          {p.id === 0 ? (
                              <span className="text-[10px] bg-yellow-500 text-black px-2 py-1 rounded font-black uppercase tracking-wider font-sans">HOST</span>
                          ) : (
                              <span className="text-[10px] text-gray-500 font-bold uppercase tracking-wider font-sans">GUEST</span>
                          )}
                       </div>
                    ))}
                 </div>
            </div>

            {/* Game Controls */}
            {isHost ? (
                <div className="flex flex-col gap-6">
                    {/* Rounds Selector */}
                    <div className="flex flex-col gap-2">
                        <span className="text-gray-500 text-[10px] font-bold uppercase tracking-wider font-sans">ROUNDS (1-100)</span>
                        <div className="flex gap-2 justify-center">
