                            {/* Presets */}
                            {[5, 10, 20].map(r => (
                               <button 
                                   key={r} 
                                   onClick={() => updateRounds(r)} 
                                   className={`w-12 h-12 flex items-center justify-center rounded-lg text-sm font-bold transition-all border font-sans ${
                                       rounds === r 
                                       ? 'bg-yellow-500 text-black border-yellow-500 shadow-lg shadow-yellow-500/20' 
