                               >
                                   {r}
                               </button>
                            ))}
                        </div>
                    </div>

                    {/* Start Button */}
                    <button 
                        onClick={handleStart} 
                        disabled={lobbyPlayers.length < 2} 
                        className={`w-full font-bold py-4 rounded-2xl flex items-center justify-center gap-2 text-lg transition-all font-sans ${
                            lobbyPlayers.length >= 2 
                            ? 'bg-[#2a3b55] hover:bg-[#354a6b] text-white border border-blue-400/30 shadow-lg' 
                            : 'bg-[#1e293b] text-[#334155] cursor-not-allowed border border-white/5'
                        }`}
                    >
                       Start Game <Play size={22} className={lobbyPlayers.length >= 2 ? "fill-current" : "stroke-current"} />
                    </button>

                    {/* Status Text */}
                    {lobbyPlayers.length < 2 && (
                        <div className="text-xs text-yellow-600/80 flex items-center justify-center gap-2 font-medium font-sans">
                            <AlertCircle size={14} /> Waiting for at least 1 opponent...
                        </div>
                    )}
                </div>
            ) : (
                <div className="w-full bg-[#1e293b] text-gray-500 font-bold py-4 rounded-2xl flex items-center justify-center gap-2 animate-pulse border border-white/5 font-sans">
                    Waiting for Host...
                </div>
            )}

            {/* Footer Actions */}
            <div className="mt-8">
                <button onClick={handleLeave} className="text-red-400 hover:text-red-300 text-sm font-medium transition-colors hover:underline font-sans">
                    Leave Room
                </button>
            </div>
        </div>
    </div>
  );
};

