            setMyOnlineId(playerId);
            setIsGuest(true); 

            if (roomData.game_state) {
               const effectiveMode = (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') as GameMode;
               setGameState({ ...roomData.game_state, gameMode: effectiveMode });
            }
          }
        } catch (e) {
          console.error("Reconnection failed or timed out", e);
          localStorage.removeItem(SESSION_KEY);
        } finally {
          clearTimeout(reconnectTimeout);
          setIsReconnecting(false);
        }
      }
    };
    checkSession();
  }, [setRoomCode, setGameState]);

  const resetSession = () => {
    localStorage.removeItem(SESSION_KEY);
    setRoomCode('');
    setMyOnlineId(null);
    setGameState({ gameMode: null });
  };

  const hardReset = () => {
      localStorage.clear();
      window.location.reload();
  };

  if (authLoading || isReconnecting) {
    return (
      <div className="h-[100dvh] w-full bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-6 z-50 fixed inset-0 p-4 text-center">
        <div className="w-16 h-16 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin"></div>

        <div className="space-y-2">
            <h2 className="font-serif text-2xl animate-pulse">
                {authLoading ? 'Loading App Logic...' : 'Reconnecting...'}
            </h2>
            <p className="text-sm text-gray-400">Please wait a moment</p>
        </div>

        {showResetOption && (
            <div className="mt-8 p-6 bg-red-900/20 rounded-2xl border border-red-500/30 animate-in fade-in slide-in-from-bottom-4">
                <div className="flex items-center justify-center gap-2 text-red-300 mb-2 font-bold">
                    <AlertTriangle size={20} />
                    <span>Taking too long?</span>
                </div>
                <p className="text-xs text-gray-400 mb-4 max-w-xs mx-auto">
                    If the app is stuck loading, you can clear the cache and restart.
                </p>
                <button 
                    onClick={hardReset}
                    className="bg-red-600 hover:bg-red-500 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 mx-auto transition-all shadow-lg active:scale-95"
                >
                    <RefreshCw size={18} /> Reset Application
                </button>
            </div>
        )}
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Auth onGuestPlay={() => setIsGuest(true)} />;
  }

  const commonProps = { displayName: getDisplayName(), userId: session?.user?.id || 'guest', setMyOnlineId };

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<MainMenu {...commonProps} onUpdateName={handleUpdateName} isGuest={isGuest} />} />

        <Route path="/setup/single" element={<SetupSingle {...commonProps} />} />
        <Route path="/setup/multi/:count" element={<SetupMulti />} />
        <Route path="/setup/online" element={<SetupOnline {...commonProps} />} />

        <Route path="/lobby" element={<Lobby myOnlineId={myOnlineId} resetSession={resetSession} />} />
        <Route path="/game" element={<Game myOnlineId={myOnlineId} resetSession={resetSession} />} />

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import { inject } from '@vercel/analytics';
import App from './App';

// Initialize Vercel Web Analytics
inject();

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

interface ErrorBoundaryProps {
  children: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: any;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: any) {
    return { hasError: true, error };
  }

  componentDidCatch(error: any, errorInfo: any) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="p-8 text-white bg-red-900/80 min-h-screen font-mono">
          <h1 className="text-2xl font-bold mb-4">Something went wrong</h1>
          <pre className="bg-black/50 p-4 rounded overflow-auto text-sm">
            {this.state.error?.toString()}
          </pre>
          <button 
            onClick={() => window.location.reload()} 
            className="mt-4 bg-white text-red-900 px-4 py-2 rounded font-bold"
          >
            Reload App
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  </React.StrictMode>
);

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { supabase } from './services/supabase';
import Auth from './components/Auth';
import MainMenu from './src/pages/MainMenu';
import { SetupSingle, SetupMulti, SetupOnline } from './src/pages/Setup';
import Lobby from './src/pages/Lobby';
import Game from './src/pages/Game';
import { useGameStore } from './src/store/gameStore';
import { RefreshCw, AlertTriangle, ArrowRight } from 'lucide-react';
import { getRoomData } from './services/online';
import { GameMode } from './types';

const SESSION_KEY = 'TRI_STACK_SESSION';
const NAME_KEY = 'TRI_STACK_PLAYER_NAME';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [isGuest, setIsGuest] = useState(false);
  const [authLoading, setAuthLoading] = useState(true);
  const [isReconnecting, setIsReconnecting] = useState(false);
  const [showResetOption, setShowResetOption] = useState(false);

  // Persistent Name
  const [customDisplayName, setCustomDisplayName] = useState('');

  // Store actions for reconnection
  const setRoomCode = useGameStore(s => s.setRoomCode);
  const setGameState = useGameStore(s => s.setGameState);

  // Who am I online?
  const [myOnlineId, setMyOnlineId] = useState<number | null>(null);

  const mountedRef = useRef(false);

  // --- Auth & Persist Name ---
  useEffect(() => {
    mountedRef.current = true;
    console.log("App mounted, initializing auth...");

    // Safety timeout: If Supabase hangs, force load after 1s
    const timeout = setTimeout(() => {
      if (mountedRef.current && authLoading) {
        console.warn("Auth check timed out, defaulting to loaded state");
        setAuthLoading(false);
      }
    }, 1000);

    // Failsafe: Show manual controls if loading takes > 3s
    const resetTimeout = setTimeout(() => {
       if (mountedRef.current && (authLoading || isReconnecting)) {
          setShowResetOption(true);
       }
    }, 3000);

    // Attempt to fetch session
    const initAuth = async () => {
        try {
            const { data: { session }, error } = await supabase.auth.getSession();
            if (error) throw error;
            if (mountedRef.current) {
                console.log("Session fetched", session ? "User logged in" : "No user");
                setSession(session);
                // Only clear loading if we didn't already timeout
                setAuthLoading(false);
            }
        } catch (err) {
            console.error("Auth Error:", err);
            if (mountedRef.current) setAuthLoading(false);
        }
    };

    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      if(mountedRef.current) setSession(session);
    });

    const savedName = localStorage.getItem(NAME_KEY);
    if (savedName) setCustomDisplayName(savedName);

    return () => {
      mountedRef.current = false;
      clearTimeout(timeout);
      clearTimeout(resetTimeout);
      subscription.unsubscribe();
    };
  }, []);

  const getDisplayName = () => {
    if (customDisplayName) return customDisplayName;
    return isGuest ? 'Guest' : (session?.user?.email?.split('@')[0] || 'Player');
  };

  const handleUpdateName = (name: string) => {
    setCustomDisplayName(name);
    localStorage.setItem(NAME_KEY, name);
  };

  // --- Session Reconnection ---
  useEffect(() => {
    const checkSession = async () => {
      const savedSession = localStorage.getItem(SESSION_KEY);
      if (savedSession) {
        console.log("Found saved session, attempting reconnect...");
        setIsReconnecting(true);

        // Safety timeout for reconnection specifically
        const reconnectTimeout = setTimeout(() => {
             if (mountedRef.current) {
                 console.warn("Reconnection timed out - forcing continue");
                 setIsReconnecting(false);
             }
        }, 2000);

        try {
          const { code, playerId } = JSON.parse(savedSession);

          // Use a simple promise race
          const roomDataPromise = getRoomData(code);
          const timeoutPromise = new Promise((_, reject) => setTimeout(() => reject(new Error("Timeout")), 1500));

          const { data: roomData, error } = await Promise.race([roomDataPromise, timeoutPromise]) as any;

          if (error || !roomData) {
            console.log("Saved session invalid or room closed.");
            localStorage.removeItem(SESSION_KEY);
          } else {
            console.log("Reconnected to room:", code);
            setRoomCode(code);
            setMyOnlineId(playerId);
            setIsGuest(true); 

            if (roomData.game_state) {
               const effectiveMode = (playerId === 0 ? 'ONLINE_HOST' : 'ONLINE_CLIENT') as GameMode;
               setGameState({ ...roomData.game_state, gameMode: effectiveMode });
            }
          }
        } catch (e) {
          console.error("Reconnection failed or timed out", e);
          localStorage.removeItem(SESSION_KEY);
        } finally {
          clearTimeout(reconnectTimeout);
          if (mountedRef.current) setIsReconnecting(false);
        }
      }
    };

    // Only run this check if auth is done or timed out
    if (!authLoading) {
        checkSession();
    }
  }, [authLoading, setRoomCode, setGameState]);

  const resetSession = () => {
    localStorage.removeItem(SESSION_KEY);
    setRoomCode('');
    setMyOnlineId(null);
    setGameState({ gameMode: null });
  };

  const hardReset = () => {
      localStorage.clear();
      window.location.reload();
  };

  const forceEnter = () => {
      setAuthLoading(false);
      setIsReconnecting(false);
      setIsGuest(true);
  };

  if (authLoading || isReconnecting) {
    return (
      <div className="h-[100dvh] w-full bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-6 z-50 fixed inset-0 p-4 text-center">
        <div className="w-16 h-16 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin"></div>

        <div className="space-y-2">
            <h2 className="font-serif text-2xl animate-pulse">
                {authLoading ? 'Initializing...' : 'Reconnecting...'}
            </h2>
            <p className="text-sm text-gray-400">Please wait a moment</p>
        </div>

        {showResetOption && (
            <div className="mt-8 p-6 bg-slate-900/50 rounded-2xl border border-white/10 animate-in fade-in slide-in-from-bottom-4 flex flex-col gap-4">
                <div className="flex items-center justify-center gap-2 text-yellow-500 mb-1 font-bold">
                    <AlertTriangle size={20} />
                    <span>Taking too long?</span>
                </div>

                <button 
                    onClick={forceEnter}
                    className="bg-green-600 hover:bg-green-500 text-white px-6 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95"
                >
                    <ArrowRight size={18} /> Play Offline / Guest
                </button>

                <button 
                    onClick={hardReset}
                    className="text-red-400 hover:text-red-300 text-sm font-bold flex items-center justify-center gap-2 transition-all"
                >
                    <RefreshCw size={14} /> Clear Cache & Reload
                </button>
            </div>
        )}
      </div>
    );
  }

  if (!session && !isGuest) {
    return <Auth onGuestPlay={() => setIsGuest(true)} />;
  }

  const commonProps = { displayName: getDisplayName(), userId: session?.user?.id || 'guest', setMyOnlineId };

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<MainMenu {...commonProps} onUpdateName={handleUpdateName} isGuest={isGuest} />} />

        <Route path="/setup/single" element={<SetupSingle {...commonProps} />} />
        <Route path="/setup/multi/:count" element={<SetupMulti />} />
        <Route path="/setup/online" element={<SetupOnline {...commonProps} />} />

        <Route path="/lobby" element={<Lobby myOnlineId={myOnlineId} resetSession={resetSession} />} />
        <Route path="/game" element={<Game myOnlineId={myOnlineId} resetSession={resetSession} />} />

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

